// Extract chatId and user input from turn
const turnResponse = $('Get Turn').item?.json ?? {};
const turn = turnResponse.data?.turn ?? turnResponse.turn ?? turnResponse;
if (!turn || typeof turn !== 'object') {
  throw new Error('AISMR workflow could not load conversation turn details.');
}
const turnContent = typeof turn.content === 'string' ? turn.content.trim() : '';
if (!turnContent) {
  throw new Error('AISMR workflow could not find user turn content.');
}
const chatId = turn.metadata?.chatId ?? turn.metadata?.telegramChatId ?? null;
if (!chatId) {
  console.warn('No chatId found in turn metadata - progress updates will fail');
}

return {
  json: {
    chatId,
    userInput: turnContent,
    turn,
    turnId: turn.id ?? $('When Executed by Another Workflow').item?.json?.turnId ?? $json.turnId
  }
};

const runResponse = $('Create Run').item?.json ?? {};
const workflowRun = runResponse.workflowRun ?? runResponse.data?.workflowRun ?? runResponse;
if (!workflowRun || !workflowRun.id) {
  throw new Error('AISMR workflow could not load workflow run details.');
}
const chatData = $('Extract ChatId').item?.json ?? {};
const runId = workflowRun.id;

return {
  json: {
    runId,
    workflowRun,
    chatId: chatData.chatId,
    userInput: chatData.userInput,
    turn: chatData.turn,
    turnId: chatData.turnId
  }
};

