// Store runId in execution custom data for error handler
const runResponse = $json ?? {};
const workflowRun = runResponse.workflowRun ?? runResponse.data?.workflowRun ?? runResponse;
const runId = workflowRun?.id;

if (runId) {
  $execution.customData.set('runId', runId);
}

return {
  json: {
    ...runResponse,
    workflowRun,
    runId
  }
};

// Try to extract runId and chatId from various sources
const errorData = $json ?? {};
const execution = errorData.execution ?? {};

// Try to get runId from execution custom data
let runId = $execution.customData?.get('runId');
let chatId = null;

// If not found, try to extract from Create Run node if it executed
if (!runId) {
  try {
    const createRunResponse = $('Create Run').item?.json ?? {};
    runId = createRunResponse.workflowRun?.id ??
      createRunResponse.data?.workflowRun?.id ??
      createRunResponse.data?.run?.id ??
      createRunResponse.run?.id ??
      createRunResponse.id;
  } catch (e) {
    // Node may not have executed
  }
}

// Try to get chatId from Extract ChatId node if it executed
if (!chatId) {
  try {
    const chatData = $('Extract ChatId').item?.json ?? {};
    chatId = chatData.chatId;
  } catch (e) {
    // Node may not have executed
  }
}

// Try to get chatId from Get Turn node if it executed
if (!chatId) {
  try {
    const turnResponse = $('Get Turn').item?.json ?? {};
    const turn = turnResponse.data?.turn ?? turnResponse.turn ?? turnResponse;
    chatId = turn?.metadata?.chatId ?? turn?.metadata?.telegramChatId;
  } catch (e) {
    // Node may not have executed
  }
}

// If still not found, try to get from Assemble Context if it executed
if (!runId || !chatId) {
  try {
    const context = $('Assemble Context').item?.json ?? {};
    if (!runId) runId = context.runId;
    if (!chatId) chatId = context.chatId;
  } catch (e) {
    // Node may not have executed
  }
}

// Extract error message
const errorMessage = execution.error?.message ?? errorData.error?.message ?? 'Unknown error in AISMR workflow';
const errorStack = execution.error?.stack ?? errorData.error?.stack ?? '';

return {
  json: {
    runId,
    chatId,
    errorMessage,
    errorStack,
    executionId: execution.id ?? null,
    lastNodeExecuted: execution.lastNodeExecuted ?? null,
    errorData
  }
};

