={{ (() => {
  const runPayload =
    $json.workflowRun ??
    $json.data?.workflowRun ??
    $json.data?.run ??
    $json.run ??
    $json;

  const stageOutput = runPayload?.stages?.idea_generation?.output ?? null;
  const candidateIdeas = [
    Array.isArray(stageOutput?.ideas) ? stageOutput.ideas : null,
    Array.isArray(runPayload?.output?.ideas) ? runPayload.output.ideas : null,
    Array.isArray(runPayload?.result) ? runPayload.result : null
  ];
  const ideas = candidateIdeas.find(Array.isArray) ?? [];

  const userIdea =
    runPayload?.input?.userIdea ??
    runPayload?.input?.user_input ??
    runPayload?.input?.userInput ??
    runPayload?.metadata?.userIdea ??
    '';

  return ({
    workflowRunId: $('Assemble Context').item.json.runId,
    stage: 'idea_generation',
    content: {
      ideas,
      userIdea,
      totalIdeas: Array.isArray(ideas) ? ideas.length : 0
    },
    notifyChannels: ['slack']
  });
})() }}

