const runId = $('Assemble Context').item.json.runId;
const chatId = $('Assemble Context').item.json.chatId;

return {
  json: {
    runId,
    chatId,
    error: 'Failed to create HITL approval request',
    status: 'failed',
    timestamp: new Date().toISOString()
  }
};

// Loop back to check approval status
const approvalId = $('Request HITL Approval').item.json.approval?.id;
const workflowRunId = $('Assemble Context').item.json.runId;

return [{
  json: {
    approvalId,
    workflowRunId,
    loopCount: ($input.all().length > 0 && $input.item(0).json.loopCount ? $input.item(0).json.loopCount + 1 : 1),
    maxLoops: 100
  }
}];

const runId = $('Assemble Context').item.json.runId;
const chatId = $('Assemble Context').item.json.chatId;
const approvalId = $('Prepare Loop').item.json.approvalId;

return {
  json: {
    runId,
    chatId,
    approvalId,
    error: 'Approval timed out after 100 polling attempts',
    status: 'timeout',
    timestamp: new Date().toISOString()
  }
};

const runId = $('Assemble Context').item.json.runId;
const chatId = $('Assemble Context').item.json.chatId;
const approvalId = $('Get Approval Status').item.json.approvalId || $('Prepare Loop').item.json.approvalId;

return {
  json: {
    runId,
    chatId,
    approvalId,
    error: 'User rejected the approval',
    status: 'rejected',
    timestamp: new Date().toISOString()
  }
};

// Extract selected idea from Generate Ideas workflow output
// Generate Ideas now returns the approved idea directly after handling HITL
const generateIdeasOutput = $('Call Generate Ideas').item.json;

// Generate Ideas returns: { ideas, selectedIdea, approvalId, userIdea, totalIdeas }
const selectedIdea = generateIdeasOutput.selectedIdea || null;
const ideas = generateIdeasOutput.ideas || [];
const approvalId = generateIdeasOutput.approvalId || null;

// Extract videoId from selectedIdea
let videoId = null;
if (selectedIdea) {
  videoId = selectedIdea.videoId || selectedIdea.ideaId || null;
} else if (ideas.length > 0) {
  // Fallback to first idea if no selection
  const firstIdea = ideas[0];
  videoId = firstIdea.videoId || firstIdea.ideaId || null;
}

return {
  json: {
    selectedIdea: selectedIdea || (ideas.length > 0 ? ideas[0] : null),
    selectedItem: selectedIdea?.ideaId || (ideas.length > 0 ? ideas[0]?.ideaId : null),
    ideas: ideas,
    approvalId: approvalId,
    videoId: videoId,
    idea: selectedIdea || (ideas.length > 0 ? ideas[0] : null),
    runId: $('Assemble Context').item.json.runId,
    chatId: $('Assemble Context').item.json.chatId,
    userInput: $('Assemble Context').item.json.userInput
  }
};

const runId = $('Assemble Context').item.json.runId;
const videoId = $('Extract Selected Idea').item.json.videoId;
const tiktokUrl = $('Call Post to TikTok').item.json.videoUrl || 
                  $('Call Post to TikTok').item.json.url ||
                  'Unknown';
const driveUrl = $('Call Upload to Google Drive').item.json.fileUrl ||
                 $('Call Upload to Google Drive').item.json.webViewLink ||
                 'Unknown';

return {
  json: {
    runId,
    status: 'completed',
    completedAt: new Date().toISOString(),
    output: {
      videoId,
      tiktokUrl,
      driveUrl
    }
  }
};
